self.addEventListener("push",i=>{try{let t=i.data?i.data.json():{},o=t.title||"MeTask Notification",n={body:t.body||"Bạn c\xf3 th\xf4ng b\xe1o mới từ MeTask!",icon:t.icon||"/favicon.ico",badge:t.badge||"/favicon.ico",data:{url:t.data?.url||"/dashboard"}};i.waitUntil(self.registration.showNotification(o,n))}catch(o){console.error("Error displaying push notification",o);let t=i.data?i.data.text():"Bạn c\xf3 th\xf4ng b\xe1o mới!";i.waitUntil(self.registration.showNotification("MeTask",{body:t,icon:"/favicon.ico",badge:"/favicon.ico",data:{url:"/dashboard"}}))}}),self.addEventListener("notificationclick",i=>{i.notification.close(),i.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{let o=i.notification.data.url;for(let i of t)if(i.url.includes(o)&&"focus"in i)return i.focus();if(self.clients.openWindow)return self.clients.openWindow(o)}))});